function connectSticks(sticks) {
    const minHeap = new MinHeap(sticks);

    let cost = 0;
    while (minHeap.size() > 1) {
        const first = minHeap.poll();
        const second = minHeap.poll();
        cost += first + second;
        minHeap.offer(first + second);
    }
    return cost;
}

class MinHeap {
    constructor(items) {
        this.heap = [];
        for (const item of items) {
            this.offer(item);
        }
    }

    offer(value) {
        this.heap.push(value);
        this.bubbleUp(this.heap.length - 1);
    }

    poll() {
        const min = this.heap[0];
        this.heap[0] = this.heap.pop();
        this.bubbleDown(0);
        return min;
    }

    size() {
        return this.heap.length;
    }

    bubbleUp(index) {
        if (index === 0) return;
        const parentIndex = Math.floor((index - 1) / 2);
        if (this.heap[parentIndex] > this.heap[index]) {
            [this.heap[parentIndex], this.heap[index]] = [this.heap[index], this.heap[parentIndex]];
            this.bubbleUp(parentIndex);
        }
    }

    bubbleDown(index) {
        const leftChildIndex = 2 * index + 1;
        const rightChildIndex = 2 * index + 2;

        let minIndex = index;
        if (leftChildIndex < this.heap.length && this.heap[leftChildIndex] < this.heap[minIndex]) {
            minIndex = leftChildIndex;
        }

        if (rightChildIndex < this.heap.length && this.heap[rightChildIndex] < this.heap[minIndex]) {
            minIndex = rightChildIndex;
        }

        if (minIndex !== index) {
            [this.heap[minIndex], this.heap[index]] = [this.heap[index], this.heap[minIndex]];
            this.bubbleDown(minIndex);
        }
    }
}
```

    The algorithm works by turning the input array `sticks` into a min heap, a data structure that allows for efficient retrieval of the smallest element in the heap. The algorithm then iterates until there is only one stick left, removing the two smallest sticks from the heap, combining them and adding their sum back into the heap. The cost of combining the two sticks is added to the total cost. After all the sticks have been combined, the function returns the total cost. The algorithm has a time complexity of O(n log n) where n is the number of elements in the input array, as each operation in the heap takes O(log n) time, and we perform about n operations.

